-- Comite Nacional PRM - Distrito Nacional: esquema + datos semilla

create table if not exists public.dirigentes (
  id bigint generated always as identity primary key,
  grupo text not null check (grupo in ('32','172')),
  numero_orden int,
  cedula text,
  nombre text not null,
  cargo text,
  ubicacion text,
  preferencia text check (preferencia in ('DC','CM','WA','GG','YL','TP')),
  updated_at timestamptz not null default now()
);

create unique index if not exists dirigentes_grupo_orden_idx on public.dirigentes(grupo, numero_orden);

alter table public.dirigentes enable row level security;

drop policy if exists "lectura publica" on public.dirigentes;
create policy "lectura publica" on public.dirigentes for select using (true);

-- Sin politica de escritura publica: las actualizaciones de preferencia
-- se hacen desde el servidor (service role) tras validar la contrasena de la app.

-- 32 miembros del Comite Nacional
on conflict (grupo, numero_orden) do nothing;

-- 172 miembros (Padron Fotografico - Directorio Institucional)
on conflict (grupo, numero_orden) do nothing;
